class AuthManager(private val context: Context) {
    private val sharedPreferences = context.getSharedPreferences("Auth", Context.MODE_PRIVATE)
    
    fun saveTokenAndId(authToken: String, userId: String) {
        with(sharedPreferences.edit()) {
            putString("AUTH_TOKEN", authToken)
            putString("USER_ID", userId)
            apply()
        }
    }
    
    fun getAuthToken(): String? = sharedPreferences.getString("AUTH_TOKEN", null)
    
    fun getUserId(): String? = sharedPreferences.getString("USER_ID", null)
